/* Aula 03 — modelJs: Variáveis e Tipos */

// 1) const (não reatribui)
const seuNome = 'Bruno';
const suaIdade = 27;
const estaEstudando = true;

console.log('nome:', seuNome);
console.log('idade:', suaIdade);
console.log('estudando:', estaEstudando);

// 2) let (reatribui)
let pontos = 0;
console.log('pontos inicial:', pontos);

pontos = pontos + 10;
console.log('pontos depois de +10:', pontos);

pontos = pontos + 5;
console.log('pontos depois de +5:', pontos);

// 3) typeof (inspecionar tipo)
console.log('typeof nome:', typeof seuNome);
console.log('typeof idade:', typeof suaIdade);
console.log('typeof estudando:', typeof estaEstudando);
console.log('typeof pontos:', typeof pontos);

// 4) undefined e null
let x;
let usuario = null;
console.log('x:', x, 'typeof:', typeof x);
console.log('usuario:', usuario, 'typeof:', typeof usuario); // pegadinha: object
